import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"70B. Special Disaster Leave","description":"","frontmatter":{"title":"70B. Special Disaster Leave","eba":"Doctors in Training 2022-2026","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/70B-special-disaster-leave.md","filePath":"ebas/doctors-in-training/leave/70B-special-disaster-leave.md"}'),o={name:"ebas/doctors-in-training/leave/70B-special-disaster-leave.md"};function i(n,e,l,c,p,d){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_70b-special-disaster-leave" tabindex="-1">70B. Special Disaster Leave <a class="header-anchor" href="#_70b-special-disaster-leave" aria-label="Permalink to &quot;70B. Special Disaster Leave&quot;">​</a></h1><p><strong>70B.1</strong> Special disaster leave of up to 3 days per calendar year is payable where:</p><p><strong>(a)</strong> the Doctor is a full time or part time Doctor;</p><p><strong>(b)</strong> Personal Leave is not available either because the Doctor has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(c)</strong> the Doctor is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Doctor&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(ii)</strong> the lives or safety of their immediate family or household members are threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Doctor&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p>70B.2. Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, flood, bushfire.</p>',10)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
